import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces_NoArg() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat modified = original.withIgnoreSurroundingSpaces();

        assertNotNull(modified);
        assertTrue(modified.getIgnoreSurroundingSpaces());
        // Ensure original is unchanged (immutable pattern)
        assertFalse(original.getIgnoreSurroundingSpaces());
    }

    @Test
    void testWithIgnoreSurroundingSpaces_BooleanTrue() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        // Use reflection to invoke private withIgnoreSurroundingSpaces(boolean)
        java.lang.reflect.Method method = CSVFormat.class.getDeclaredMethod("withIgnoreSurroundingSpaces", boolean.class);
        method.setAccessible(true);
        CSVFormat result = (CSVFormat) method.invoke(original, true);

        assertNotNull(result);
        assertTrue(result.getIgnoreSurroundingSpaces());
        assertFalse(original.getIgnoreSurroundingSpaces());
    }

    @Test
    void testWithIgnoreSurroundingSpaces_BooleanFalse() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces(true);
        java.lang.reflect.Method method = CSVFormat.class.getDeclaredMethod("withIgnoreSurroundingSpaces", boolean.class);
        method.setAccessible(true);
        CSVFormat result = (CSVFormat) method.invoke(original, false);

        assertNotNull(result);
        assertFalse(result.getIgnoreSurroundingSpaces());
        assertTrue(original.getIgnoreSurroundingSpaces());
    }
}
